// To parse this JSON data, do
//
//     final tsconfig = tsconfigFromJson(jsonString);

import 'dart:convert';

Tsconfig tsconfigFromJson(String str) => Tsconfig.fromJson(json.decode(str));

String tsconfigToJson(Tsconfig data) => json.encode(data.toJson());

class Tsconfig {
    CompilerOptions compilerOptions;
    List<String> include;
    List<String> exclude;
    bool compileOnSave;
    bool buildOnSave;

    Tsconfig({
        required this.compilerOptions,
        required this.include,
        required this.exclude,
        required this.compileOnSave,
        required this.buildOnSave,
    });

    factory Tsconfig.fromJson(Map<String, dynamic> json) => Tsconfig(
        compilerOptions: CompilerOptions.fromJson(json["compilerOptions"]),
        include: List<String>.from(json["include"].map((x) => x)),
        exclude: List<String>.from(json["exclude"].map((x) => x)),
        compileOnSave: json["compileOnSave"],
        buildOnSave: json["buildOnSave"],
    );

    Map<String, dynamic> toJson() => {
        "compilerOptions": compilerOptions.toJson(),
        "include": List<dynamic>.from(include.map((x) => x)),
        "exclude": List<dynamic>.from(exclude.map((x) => x)),
        "compileOnSave": compileOnSave,
        "buildOnSave": buildOnSave,
    };
}

class CompilerOptions {
    String target;
    String module;
    String moduleResolution;
    String outDir;
    bool isolatedModules;
    bool experimentalDecorators;
    bool emitDecoratorMetadata;
    bool declaration;
    bool noImplicitAny;
    bool suppressImplicitAnyIndexErrors;
    bool strictNullChecks;
    bool noImplicitReturns;
    bool noFallthroughCasesInSwitch;
    bool noUnusedLocals;
    bool noUnusedParameters;
    bool removeComments;
    bool noLib;
    bool preserveConstEnums;
    bool sourceMap;
    bool watch;
    List<String> typeRoots;

    CompilerOptions({
        required this.target,
        required this.module,
        required this.moduleResolution,
        required this.outDir,
        required this.isolatedModules,
        required this.experimentalDecorators,
        required this.emitDecoratorMetadata,
        required this.declaration,
        required this.noImplicitAny,
        required this.suppressImplicitAnyIndexErrors,
        required this.strictNullChecks,
        required this.noImplicitReturns,
        required this.noFallthroughCasesInSwitch,
        required this.noUnusedLocals,
        required this.noUnusedParameters,
        required this.removeComments,
        required this.noLib,
        required this.preserveConstEnums,
        required this.sourceMap,
        required this.watch,
        required this.typeRoots,
    });

    factory CompilerOptions.fromJson(Map<String, dynamic> json) => CompilerOptions(
        target: json["target"],
        module: json["module"],
        moduleResolution: json["moduleResolution"],
        outDir: json["outDir"],
        isolatedModules: json["isolatedModules"],
        experimentalDecorators: json["experimentalDecorators"],
        emitDecoratorMetadata: json["emitDecoratorMetadata"],
        declaration: json["declaration"],
        noImplicitAny: json["noImplicitAny"],
        suppressImplicitAnyIndexErrors: json["suppressImplicitAnyIndexErrors"],
        strictNullChecks: json["strictNullChecks"],
        noImplicitReturns: json["noImplicitReturns"],
        noFallthroughCasesInSwitch: json["noFallthroughCasesInSwitch"],
        noUnusedLocals: json["noUnusedLocals"],
        noUnusedParameters: json["noUnusedParameters"],
        removeComments: json["removeComments"],
        noLib: json["noLib"],
        preserveConstEnums: json["preserveConstEnums"],
        sourceMap: json["sourceMap"],
        watch: json["watch"],
        typeRoots: List<String>.from(json["typeRoots"].map((x) => x)),
    );

    Map<String, dynamic> toJson() => {
        "target": target,
        "module": module,
        "moduleResolution": moduleResolution,
        "outDir": outDir,
        "isolatedModules": isolatedModules,
        "experimentalDecorators": experimentalDecorators,
        "emitDecoratorMetadata": emitDecoratorMetadata,
        "declaration": declaration,
        "noImplicitAny": noImplicitAny,
        "suppressImplicitAnyIndexErrors": suppressImplicitAnyIndexErrors,
        "strictNullChecks": strictNullChecks,
        "noImplicitReturns": noImplicitReturns,
        "noFallthroughCasesInSwitch": noFallthroughCasesInSwitch,
        "noUnusedLocals": noUnusedLocals,
        "noUnusedParameters": noUnusedParameters,
        "removeComments": removeComments,
        "noLib": noLib,
        "preserveConstEnums": preserveConstEnums,
        "sourceMap": sourceMap,
        "watch": watch,
        "typeRoots": List<dynamic>.from(typeRoots.map((x) => x)),
    };
}
